SELECT 
  (SELECT COUNT(*) FROM sensor_data) AS total_sensor_data,
  (SELECT COUNT(*) FROM devices WHERE status = 'active') AS total_active_devices;

SELECT sd.*
FROM sensor_data sd
WHERE sd.data_quality IS NOT NULL;

SELECT sd.device_id, sd.time_utc, sd.x_axis_g
FROM sensor_data sd
WHERE sd.x_axis_g > (
    SELECT AVG(x_axis_g) FROM sensor_data
);
